// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract LendingPool is ReentrancyGuard, Ownable {
    IERC20 public usdc;
    address public loanManager;

    mapping(address => uint256) public deposits;
    uint256 public totalDeposits;
    uint256 public totalBorrowed;

    uint256 public constant BPS_DENOMINATOR = 10000;

    constructor(address _usdc) Ownable(msg.sender) {
        usdc = IERC20(_usdc);
    }

    modifier onlyLoanManager() {
        require(msg.sender == loanManager, "not loan manager");
        _;
    }

    function setLoanManager(address manager) external onlyOwner {
        require(manager != address(0), "manager=0");
        loanManager = manager;
    }

    function deposit(uint256 amount) external nonReentrant {
        require(amount > 0, "amount=0");
        require(usdc.transferFrom(msg.sender, address(this), amount), "transfer failed");
        deposits[msg.sender] += amount;
        totalDeposits += amount;
    }

    function withdraw(uint256 amount) external nonReentrant {
        require(amount > 0, "amount=0");
        require(deposits[msg.sender] >= amount, "insufficient deposit");
        require(availableLiquidity() >= amount, "insufficient liquidity");
        deposits[msg.sender] -= amount;
        totalDeposits -= amount;
        require(usdc.transfer(msg.sender, amount), "transfer failed");
    }

    function lend(address to, uint256 amount) external nonReentrant onlyLoanManager {
        require(amount > 0, "amount=0");
        require(availableLiquidity() >= amount, "insufficient liquidity");
        totalBorrowed += amount;
        require(usdc.transfer(to, amount), "transfer failed");
    }

    function repay(uint256 amount) external nonReentrant onlyLoanManager {
        require(amount > 0, "amount=0");
        require(totalBorrowed >= amount, "repay>debt");
        totalBorrowed -= amount;
    }

    function utilizationRateBps() public view returns (uint256) {
        if (totalDeposits == 0) {
            return 0;
        }
        return (totalBorrowed * BPS_DENOMINATOR) / totalDeposits;
    }

    function getInterestRateBps() public view returns (uint256) {
        return utilizationRateBps() > 5000 ? 1000 : 500; // 10% or 5%
    }

    function availableLiquidity() public view returns (uint256) {
        return totalDeposits - totalBorrowed;
    }
}

contracts/LoanManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./ValuationEngine.sol";
import "./VestingAdapter.sol";
import "./LendingPool.sol";

contract LoanManager {
    ValuationEngine public valuation;
    VestingAdapter public adapter;
    LendingPool public pool;

    struct Loan {
        address borrower;
        uint256 principal;
        uint256 interest;
        uint256 collateralId;
        uint256 unlockTime;
        bool active;
    }

    mapping(uint256 => Loan) public loans;
    uint256 public loanCount;

    event LoanCreated(uint256 indexed loanId, address indexed borrower, uint256 amount);
    event LoanRepaid(uint256 indexed loanId, uint256 amount);
    event LoanSettled(uint256 indexed loanId, bool defaulted);

    constructor(address _valuation, address _adapter, address _pool) {
        valuation = ValuationEngine(_valuation);
        adapter = VestingAdapter(_adapter);
        pool = LendingPool(_pool);
    }

    function createLoan(
        uint256 collateralId,
        address vestingContract,
        uint256 borrowAmount
    ) external {
        require(borrowAmount > 0, "amount=0");

        adapter.escrow(collateralId, vestingContract);
        (uint256 quantity, address token, uint256 unlockTime) = adapter.getDetails(collateralId);

        (uint256 pv, uint256 ltvBps) = valuation.computeDPV(quantity, token, unlockTime);
        uint256 maxBorrow = (pv * ltvBps) / 10000;
        require(borrowAmount <= maxBorrow, "exceeds LTV");

        uint256 interestRateBps = pool.getInterestRateBps();
        uint256 interest = (borrowAmount * interestRateBps) / 10000;

        uint256 loanId = loanCount;
        loans[loanId] = Loan({
            borrower: msg.sender,
            principal: borrowAmount,
            interest: interest,
            collateralId: collateralId,
            unlockTime: unlockTime,
            active: true
        });
        loanCount += 1;

        pool.lend(msg.sender, borrowAmount);
        emit LoanCreated(loanId, msg.sender, borrowAmount);
    }

    function repayLoan(uint256 loanId, uint256 amount) external {
        Loan storage loan = loans[loanId];
        require(loan.active, "inactive");
        require(msg.sender == loan.borrower, "not borrower");
        require(amount > 0, "amount=0");

        IERC20 usdc = pool.usdc();
        require(usdc.transferFrom(msg.sender, address(pool), amount), "transfer failed");
        pool.repay(amount);

        uint256 remainingInterest = loan.interest;
        uint256 remainingPrincipal = loan.principal;

        if (amount >= remainingInterest) {
            loan.interest = 0;
            uint256 principalPaid = amount - remainingInterest;
            if (principalPaid >= remainingPrincipal) {
                loan.principal = 0;
                loan.active = false;
            } else {
                loan.principal = remainingPrincipal - principalPaid;
            }
        } else {
            loan.interest = remainingInterest - amount;
        }

        emit LoanRepaid(loanId, amount);
    }

    function settleAtUnlock(uint256 loanId) external {
        Loan storage loan = loans[loanId];
        require(loan.active, "inactive");
        require(block.timestamp >= loan.unlockTime, "not unlocked");

        bool defaulted = loan.principal + loan.interest > 0;
        loan.active = false;
        loan.principal = 0;
        loan.interest = 0;

        emit LoanSettled(loanId, defaulted);
    }
}

